import{_ as t,o as a,c as r,ag as n}from"./chunks/framework.eQLvDOR_.js";const u=JSON.parse('{"title":"agent-curated-memory","description":"","frontmatter":{"title":"agent-curated-memory","concept":"Agent 策展式记忆","concept_id":"agent-curated-memory","aliases":["Agent-Curated Memory"],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] Hermes Agent 从中级到高级进阶指南.md"],"related_concepts":["[[memory-nudge-mechanism]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/agent-curated-memory.md","filePath":"wiki/concepts/agent-curated-memory.md","lastUpdated":null}'),o={name:"wiki/concepts/agent-curated-memory.md"};function c(i,e,m,d,l,s){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="agent-策展式记忆-agent-curated-memory" tabindex="-1">Agent 策展式记忆 (Agent-Curated Memory) <a class="header-anchor" href="#agent-策展式记忆-agent-curated-memory" aria-label="Permalink to &quot;Agent 策展式记忆 (Agent-Curated Memory)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>区别于全量记录聊天对话，策展式记忆指的是由 Agent 在后台主动判断、精炼并覆盖更新特定知识库（如 <code>MEMORY.md</code>），作为系统高价值、高密度的永久记忆存储机制。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>避免前缀污染</strong>：全量历史写入会导致 KV Cache 前缀在每轮对话中剧烈改变，破坏缓存并带来灾难性的推理成本。冻结快照设计能将头部稳定化。（来源：<a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Hermes Agent 从中级到高级进阶指南.html">[Agent_Architecture] Hermes Agent 从中级到高级进阶指南.md</a>）</li><li><strong>去重与清洗</strong>：过滤掉思维发散、临时试错的代码，只保留确定的事实（如用户的 Python 偏好路径），类似于系统梳理知识。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>使用者在意识到这是一个策展提取机制时，需要更加“指令化”。例如：不要指望 AI 自己明白刚才某个报错的解决方案是有价值的，而应使用明确指令要求“将这段修复方案列入你的底层记忆以免之后忘掉”。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/memory-nudge-mechanism.html">memory-nudge-mechanism</a> — 触发这种主观策展行为背后的定时机器齿轮。</li></ul>',9)])])}const g=t(o,[["render",c]]);export{u as __pageData,g as default};
